// Build the multimodal Gemini API request
const body = $input.first().json.body;
const images = body.images; // Array of { index, base64 }

// Build the 'parts' array: one inline_data per image + the text prompt
const parts = [];

// Add each image as an inline_data part
for (const img of images) {
  parts.push({
    inline_data: {
      mime_type: 'image/jpeg',
      data: img.base64
    }
  });
}

// Add the master prompt as the final part
parts.push({
  text: `You are a professional transcription assistant. You have been given ${images.length} image(s) of handwritten notes, essays, or mind maps.

Your task:
1. CAREFULLY read the handwriting in each image, in the exact order they were provided (Image 1, Image 2, etc.).
2. UNDERSTAND the logical flow and context across all pages — they form a single continuous document.
3. TRANSCRIBE the handwriting into clean, well-structured digital text.
4. PRESERVE the author's original intent, ideas, paragraph structure, and any headings or bullet points.
5. If the handwriting contains a mind map, convert it into a logical outline or structured text.
6. Separate content from different pages with a blank line, but maintain narrative continuity.
7. Fix obvious spelling errors in the valid handwriting, but do NOT add, remove, or rephrase the author's ideas.
8. STRICT DELETION RULE: You must COMPLETELY IGNORE any text that is visibly crossed out or marked for deletion. This includes:
   - Single letters or words with a line drawn through them.
   - Entire sentences with a continuous horizontal line struck through them.
   - Whole paragraphs or sections that have a large 'X' drawn over them or are boxed out.
   Do NOT transcribe these sections. Do NOT leave placeholders (like "[deleted]"). Simply skip the crossed-out text and seamlessly connect the surrounding valid words.
9. Do NOT add any commentary, preamble, or summary — output ONLY the final transcribed text.

Begin transcription now:`
});

const geminiPayload = {
  contents: [{
    parts: parts
  }],
  generationConfig: {
    temperature: 0.2,
    topP: 0.8,
    topK: 40,
    maxOutputTokens: 8192
  },
  safetySettings: [
    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
  ]
};

return { json: { geminiPayload } };

const response = $input.first().json;

// Navigate Gemini response structure
let text = '';

try {
  if (response.body && response.body.candidates && response.body.candidates.length > 0) {
    const candidate = response.body.candidates[0];
    if (candidate.content && candidate.content.parts) {
      text = candidate.content.parts
        .filter(p => p.text)
        .map(p => p.text)
        .join('\n');
    }
  }

  // Fallback: direct structure without 'body' wrapper
  if (!text && response.candidates && response.candidates.length > 0) {
    text = response.candidates[0].content.parts
      .filter(p => p.text)
      .map(p => p.text)
      .join('\n');
  }

  if (!text) {
    throw new Error('No text extracted from Gemini response');
  }
} catch (err) {
  throw new Error(`Gemini extraction failed: ${err.message}. Raw keys: ${JSON.stringify(Object.keys(response))}`);
}

return { json: { text: text.trim() } };

// This handles type: 'error_report' from the frontend
const body = $input.first().json.body;

return {
  json: {
    to: body.recipient,
    subject: `[D2D Error] ${new Date().toISOString()}`,
    htmlBody: `
      <h2>Drafts to Digital — Error Report</h2>
      <p><strong>Timestamp:</strong> ${body.timestamp}</p>
      <p><strong>User Agent:</strong> ${body.userAgent}</p>
      <p><strong>User Message:</strong> ${body.error.userMessage}</p>
      <hr/>
      <h3>Technical Detail</h3>
      <pre style="background:#f4f4f4;padding:12px;border-radius:6px;font-size:13px;overflow-x:auto;">${body.error.technicalDetail}</pre>
    `
  }
};

